const visitsToAdd = $json.visitsToAdd;

const enriched = await Promise.all(visitsToAdd.map(async (v) => {
  if (v.ip) {
    try {
      const res = await fetch('http://ip-api.com/json/' + v.ip);
      const d = await res.json();
      if (d && d.status === 'success') {
        v.country = d.country || '';
        v.countryCode = d.countryCode || '';
        v.city = d.city || '';
      }
    } catch (e) {
      // geo lookup failed, leave fields empty
    }
  }
  return v;
}));

return [{ json: { visitsToAdd: enriched } }];
